import { getBlogMdxListItems } from '#app/utils/mdx.server.ts'
import { formatDate, getDomainUrl } from '#app/utils/misc.ts'
import { type Route } from './+types/rss[.]xml'

export async function loader({ request }: Route.LoaderArgs) {
	const posts = await getBlogMdxListItems({ request })

	const blogUrl = `${getDomainUrl(request)}/blog`

	const rss = `
    <rss xmlns:blogChannel="${blogUrl}" version="2.0">
      <channel>
        <title>AbhiDev Blog</title>
        <link>${blogUrl}</link>
        <description>The AbhiDev Blog</description>
        <language>en-us</language>
        <generator>AbhiBuddy the Koala</generator>
        <ttl>40</ttl>
        ${posts
					.map((post) =>
						`
            <item>
              <title>${cdata(post.frontmatter.title ?? 'Untitled Post')}</title>
              <description>${cdata(
								post.frontmatter.description ?? 'This post is... indescribable',
							)}</description>
              <pubDate>${formatDate(
								post.frontmatter.date ?? new Date(),
								'yyyy-MM-dd',
							)}</pubDate>
              <link>${blogUrl}/${post.slug}</link>
              <guid>${blogUrl}/${post.slug}</guid>
            </item>
          `.trim(),
					)
					.join('\n')}
      </channel>
    </rss>
  `.trim()

	return new Response(rss, {
		headers: {
			'Content-Type': 'application/xml',
			'Content-Length': String(Buffer.byteLength(rss)),
		},
	})
}

function cdata(s: string) {
	return `<![CDATA[${s}]]>`
}
